import java.util.*;

public static long solve(long[] nums, long k) {
    long[] prefixXOR = new long[nums.length + 1];
    for (int i = 0; i < nums.length; i++) {
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
    }

    long[] dp = new long[k + 1];
    Arrays.fill(dp, Long.MAX_VALUE);

    dp[0] = 0;

    for (int i = 1; i <= k; i++) {
        for (int j = i - 1; j < nums.length; j++) {
            long currentXOR = prefixXOR[j + 1] ^ prefixXOR[i - 1];
            dp[i] = Math.min(dp[i], Math.max(dp[i - 1], currentXOR));
        }
    }

    return dp[(int) k];
}
